class Solution:
    def minimumScore(self, s: str, t: str) -> int:
        n, m = len(s), len(t)
        left = [-1] * m
        j = 0
        for i in range(n):
            if j < m and s[i] == t[j]:
                left[j] = i
                j += 1
        if j == m:
            return 0
        right = [-1] * m
        j = m - 1
        for i in range(n - 1, -1, -1):
            if j >= 0 and s[i] == t[j]:
                right[j] = i
                j -= 1
        res = m
        k = 0
        for i in range(m + 1):
            while k < m and (i > k or left[i] == -1 or (k < m and right[k] != -1 and left[i] >= right[k])):
                k += 1
            res = min(res, k - i)
        return res

